interface OsuModIconProps {
  mod: ModType;
  size?: number;
  className?: string;
  style?: React.CSSProperties;
}

/** osu! 官方 Mod 图标 */
export const OsuModIcon: React.FC<OsuModIconProps> = ({
  mod,
  size = 40,
  className,
  style,
}) => {
  const data = MOD_ICON_DATA[mod];
  return (
    <svg
      width={size}
      height={size}
      viewBox={data.viewBox}
      fill="none"
      className={className}
      style={{ flexShrink: 0, ...style }}
    >
      {data.paths.map((p, i) => (
        <path key={i} d={p.d} fill={p.fill} fillRule="evenodd" />
      ))}
    </svg>
  );
};